import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface CurrentQuarter {
  revenue: number;
  costs: number;
  profit: number;
  profitMarginPercent: number;
}

interface PreviousQuarter {
  revenue: number;
  costs: number;
  profit: number;
  profitMarginPercent: number;
}

interface QuarterComparison {
  quarter: string;
  revenue: number;
  profit: number;
}

interface WidgetData {
  currentQuarter: CurrentQuarter;
  previousQuarter: PreviousQuarter;
  quarterComparison: QuarterComparison[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { currentQuarter, previousQuarter, quarterComparison } = data;
  const isProfitIncreased = currentQuarter.profit > previousQuarter.profit;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF', borderRadius: 3 }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Profit Margin
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5}>
              {isProfitIncreased ? <TrendingUp sx={{ fontSize: 20, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 20, color: '#EF4444' }} />}
              <Typography variant="h4" fontWeight={700} sx={{ color: '#1976D2' }}>
                {currentQuarter.profitMarginPercent}%
              </Typography>
            </Stack>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Previous Quarter: {previousQuarter.profitMarginPercent}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: quarterComparison.map(q => q.revenue),
                  color: '#FFC107',
                  label: 'Revenue',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: quarterComparison.map(q => q.quarter),
                  id: 'quarters',
                },
              ]}
              yAxis={[{ id: 'revenue' }]}
            >
              <g clipPath={`url(#clipPathId)`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="quarters"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="revenue"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id="clipPathId" />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
